// Summary: Ensures SelectionCard checkbox role, data-selected and aria-checked states, focus ring tokens, ariaLabel normalization, icon ordering, and ref forwarding.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { SelectionCard, type SelectionCardProps } from './SelectionCard';
import { EventIcon } from '../../../icons';

const renderSelectionCard = (props?: Partial<SelectionCardProps>) => {
  return render(<SelectionCard label="Project One" icon={<EventIcon decorative />} {...props} />);
};

describe('SelectionCard', () => {
  it('renders as a checkbox with visible label and decorative icon', () => {
    const { container } = renderSelectionCard();
    const checkbox = screen.getByRole('checkbox', { name: 'Project One' });
    const labelNode = screen.getByText('Project One');
    const iconWrapper = container.querySelector('div[aria-hidden="true"]');
    const passes =
      Boolean(checkbox) &&
      Boolean(labelNode) &&
      iconWrapper?.getAttribute('aria-hidden') === 'true';
    expect(passes).toBe(true);
  });

  it.each([false, true])('syncs aria-checked with isSelected=%s', isSelected => {
    renderSelectionCard({ isSelected });
    const checkbox = screen.getByRole('checkbox', { name: 'Project One' });
    const matches = checkbox.getAttribute('aria-checked') === String(isSelected);
    expect(matches).toBe(true);
  });

  it('applies selected state classes when selected', () => {
    const { container } = renderSelectionCard({ isSelected: true });
    const root = container.firstElementChild as HTMLElement;
    const hasTokens =
      root.className.includes('border-color-border-brand') &&
      root.className.includes('border-0.5') &&
      root.getAttribute('data-selected') === 'true';
    expect(hasTokens).toBe(true);
  });

  it('includes focus-visible ring tokens on the root', () => {
    const { container } = renderSelectionCard();
    const root = container.firstElementChild as HTMLElement;
    const hasFocusTokens = root.className.includes('focus-visible-brand');
    expect(hasFocusTokens).toBe(true);
  });

  it('enforces fixed width via tokens', () => {
    const { container } = renderSelectionCard();
    const root = container.firstElementChild as HTMLElement;
    const hasWidth = root.className.includes('w-60');
    expect(hasWidth).toBe(true);
  });

  it('renders icon before label in the DOM', () => {
    const { container } = renderSelectionCard();
    const root = container.firstElementChild as HTMLElement;
    const children = Array.from(root.children) as HTMLElement[];
    const orderCorrect =
      children[0]?.getAttribute('aria-hidden') === 'true' &&
      (children[1]?.textContent ?? '').includes('Project One');
    expect(orderCorrect).toBe(true);
  });

  it('is server-renderable without the use client directive', () => {
    const functionSource = SelectionCard.toString();
    const containsUseClient =
      functionSource.includes("'use client'") || functionSource.includes('"use client"');
    expect(containsUseClient).toBe(false);
  });

  it('does not attach inline event handler attributes by default', () => {
    const { container } = renderSelectionCard();
    const root = container.firstElementChild as HTMLElement;
    const hasInlineHandlers = root
      .getAttributeNames()
      .some(attribute => attribute.startsWith('on'));
    expect(hasInlineHandlers).toBe(false);
  });

  it('normalizes ariaLabel: ignores whitespace-only and applies non-empty values', () => {
    const { container, rerender } = renderSelectionCard({ ariaLabel: '   ' });
    const root = container.firstElementChild as HTMLElement;
    const initialState = root.hasAttribute('aria-label');
    rerender(
      <SelectionCard
        label="Project One"
        icon={<EventIcon decorative />}
        ariaLabel="  Custom Name  "
      />
    );
    const updatedState =
      (container.firstElementChild as HTMLElement).getAttribute('aria-label') === 'Custom Name';
    const result = initialState === false && updatedState;
    expect(result).toBe(true);
  });

  it('omits data-selected attribute when not selected', () => {
    const { container } = renderSelectionCard({ isSelected: false });
    const root = container.firstElementChild as HTMLElement;
    const hasAttribute = root.hasAttribute('data-selected');
    expect(hasAttribute).toBe(false);
  });

  it('forwards ref to the root div element', () => {
    const ref = React.createRef<HTMLDivElement>();
    render(<SelectionCard ref={ref} label="Project One" icon={<EventIcon decorative />} />);
    const forwarded =
      ref.current instanceof HTMLDivElement && ref.current.getAttribute('role') === 'checkbox';
    expect(forwarded).toBe(true);
  });

  it('applies truncate class to the label wrapper for single-line ellipsis', () => {
    const { container } = renderSelectionCard();
    const root = container.firstElementChild as HTMLElement;
    const labelWrapper = root.children[1] as HTMLElement;
    const hasTruncate = labelWrapper.className.includes('truncate');
    expect(hasTruncate).toBe(true);
  });

  it('merges incoming className with composed base classes on the root', () => {
    const { container } = renderSelectionCard({ className: 'custom-class' });
    const root = container.firstElementChild as HTMLElement;
    const merged =
      root.className.includes('inline-flex') && root.className.includes('custom-class');
    expect(merged).toBe(true);
  });
});
